import { useState, useEffect } from 'react';
import { update } from '../services/api';
import { useSearchParams } from 'react-router-dom';
import axios from 'axios';

export default function Update() {
  const [id, setId]       = useState('');
  const [params]          = useSearchParams();
  const [loading, setLoading] = useState(false);
  const [status, setStatus]   = useState(null);

  const [form, setForm] = useState({
    documents_submitted: 0,
    police_verification: 'Pending'
  });

  useEffect(() => {
    const idParam = params.get('id');
    if (idParam) {
      setId(idParam);
      axios.get(`http://localhost:5000/applications/${idParam}`)
        .then(res => setForm({
          documents_submitted: res.data.documents_submitted,
          police_verification: res.data.police_verification
        }))
        .catch(() => setStatus('error'));
    }
  }, [params]);

  const handleUpdate = async (e) => {
    e.preventDefault();
    if (!id.trim()) { setStatus('no-id'); return; }
    setLoading(true);
    try {
      await update(id, form);
      setStatus('success');
    } catch {
      setStatus('error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page">
      <div className="container" style={{ maxWidth: 560 }}>
        <div className="page-header">
          <h2>Update Application</h2>
          <div className="divider" />
          <p>Modify the verification or document status for an application.</p>
        </div>

        <div className="card">
          {status === 'success' && (
            <div className="alert alert-success">✅ Application updated successfully.</div>
          )}
          {status === 'error' && (
            <div className="alert alert-error">⚠️ Could not find the application. Check the ID.</div>
          )}
          {status === 'no-id' && (
            <div className="alert alert-error">⚠️ Please enter an Application ID.</div>
          )}

          <form onSubmit={handleUpdate}>
            <div className="form-group">
              <label>Application ID</label>
              <input
                placeholder="e.g. 3"
                value={id}
                onChange={e => setId(e.target.value)}
              />
            </div>

            <div className="form-group">
              <label>Documents Submitted</label>
              <select
                value={form.documents_submitted}
                onChange={e => setForm({ ...form, documents_submitted: e.target.value })}
              >
                <option value={0}>No — Not yet submitted</option>
                <option value={1}>Yes — All documents in</option>
              </select>
            </div>

            <div className="form-group">
              <label>Police Verification</label>
              <select
                value={form.police_verification}
                onChange={e => setForm({ ...form, police_verification: e.target.value })}
              >
                <option value="Pending">Pending</option>
                <option value="Approved">Approved</option>
                <option value="Rejected">Rejected</option>
              </select>
            </div>

            <button
              type="submit"
              className="btn btn-primary w-full"
              disabled={loading}
              style={{ justifyContent: 'center', marginTop: 8 }}
            >
              {loading ? 'Saving…' : 'Save Changes →'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
